module RefModule(
    input wire clk,
    input wire reset,
    input wire [3:0] binary_num,
    output reg [3:0] twos_complement
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (reset) begin
            twos_complement <= 0;
        end else begin
            twos_complement <= ~binary_num + 1;
        end
    end

endmodule
